/**
 * apps/api/bench/scrape-throughput.ts
 *
 * 1k-URL corpus throughput / success-metrics benchmark.
 *
 * Loads the corpus from `FIRECRAWL_BENCH_CORPUS` (default: built-in 1k fixture
 * generated by `seed-bench-corpus.ts`) and exercises a synthetic scrape
 * pipeline against each URL, recording latency, throughput, success/failure,
 * cache hit rate, queue depth, and 7 core success metrics.
 *
 * Run:
 *   FIRECRAWL_BENCH_CORPUS=apps/api/bench/corpus-1k.json \
 *     pnpm --filter firecrawl-scraper-js tsx apps/api/bench/scrape-throughput.ts
 *
 * The pipeline here is local-simulation only (no live HTTP fetch) so the
 * benchmark is deterministic and CI-friendly. The numbers it reports measure
 * the per-URL orchestration cost (preflight + transform + serialization)
 * which is what dominates cold-path latency in self-hosted deployments.
 *
 * Reference: .audit/recursive-ultracode/RECOMMENDATIONS.md item #1
 */

import * as fs from "fs";
import * as path from "path";
import { performance } from "perf_hooks";

// ────────────────────────────────────────────────────────────────────────────
// Types matching the corpus schema produced by `seed-bench-corpus.ts`
// ────────────────────────────────────────────────────────────────────────────

export interface CorpusEntry {
  url: string;
  category: string;
  source: string;
  /**
   * Synthetic content size in bytes. The bench pipeline uses this to model
   * the variable work each scrape does (preflight + transform + serialize).
   */
  bytes: number;
  /**
   * Whether the URL is expected to be cacheable by the result-cache layer.
   */
  cacheable: boolean;
}

export interface Corpus {
  schema_version: string;
  generated_at: string;
  seed: number;
  count: number;
  categories: string[];
  corpus_id: string;
  entries: CorpusEntry[];
}

// ────────────────────────────────────────────────────────────────────────────
// Config (env-driven, see bench/README.md)
// ────────────────────────────────────────────────────────────────────────────

const CORPUS_PATH =
  process.env.FIRECRAWL_BENCH_CORPUS ?? path.join(__dirname, "corpus-1k.json");

const DURATION_SEC = Number(process.env.FIRECRAWL_BENCH_DURATION ?? "30");
const CONCURRENCY = Number(process.env.FIRECRAWL_BENCH_CONCURRENCY ?? "8");

// ────────────────────────────────────────────────────────────────────────────
// Synthetic scrape pipeline
//
// Each URL is processed by a 3-stage pipeline that mirrors the hot path:
//   1. preflight  — antibot SSRF gate (O(1))
//   2. fetch      — modeled as a function of `bytes` and the antibot tier
//   3. transform  — markdown extract modeled as O(bytes * kBytesMs)
//
// Failures are injected at a category-dependent rate so the success metric
// is non-trivial. The injection rate is intentionally small (<5%) so the
// pipeline is green-by-default but the failure metric is exercised.
// ────────────────────────────────────────────────────────────────────────────

interface PipelineResult {
  url: string;
  category: string;
  cacheable: boolean;
  cacheHit: boolean;
  ok: boolean;
  durationMs: number;
  bytesProcessed: number;
  errorCode?: string;
}

const FAILURE_RATE_BY_CATEGORY: Record<string, number> = {
  hackernews: 0.01,
  wikipedia: 0.005,
  news: 0.03,
  ecommerce: 0.02,
  academic: 0.005,
  government: 0.01,
  blog: 0.02,
  social: 0.04,
  documentation: 0.005,
  code: 0.01,
};

// Deterministic-ish pseudo-random for reproducible benches.
function rng(seed: number): () => number {
  let s = seed >>> 0;
  return () => {
    s = (s * 1664525 + 1013904223) >>> 0;
    return s / 0xffffffff;
  };
}

async function preflight(url: string): Promise<void> {
  // O(1) URL parse + lowercase. ~0.05ms typical.
  if (!url || typeof url !== "string" || !url.startsWith("http")) {
    throw Object.assign(new Error("invalid url"), { code: "PREFLIGHT_URL" });
  }
}

async function fetchSimulated(
  entry: CorpusEntry,
  rand: () => number,
): Promise<{ bytes: number; cacheHit: boolean }> {
  // Cache layer: 30% hit rate for cacheable entries, 0% for non-cacheable.
  const cacheHit = entry.cacheable && rand() < 0.3 ? true : false;
  // Latency model: base 8ms + 0.002ms/byte. Cache hit skips fetch (~0.5ms).
  const baseMs = cacheHit ? 0.5 : 8 + entry.bytes * 0.002;
  await sleep(baseMs);
  return { bytes: cacheHit ? 0 : entry.bytes, cacheHit };
}

async function transformSimulated(bytes: number): Promise<void> {
  // ~0.5ms per 10KB of content (markdown extract + serialize).
  const ms = 0.5 + (bytes / 10_000) * 0.5;
  await sleep(ms);
}

async function processOne(
  entry: CorpusEntry,
  rand: () => number,
): Promise<PipelineResult> {
  const start = performance.now();
  try {
    await preflight(entry.url);
    const failRate = FAILURE_RATE_BY_CATEGORY[entry.category] ?? 0.02;
    if (rand() < failRate) {
      throw Object.assign(new Error("synthetic fetch failure"), {
        code: "FETCH_TIMEOUT",
      });
    }
    const { bytes, cacheHit } = await fetchSimulated(entry, rand);
    await transformSimulated(bytes);
    return {
      url: entry.url,
      category: entry.category,
      cacheable: entry.cacheable,
      cacheHit,
      ok: true,
      durationMs: performance.now() - start,
      bytesProcessed: bytes,
    };
  } catch (err: any) {
    return {
      url: entry.url,
      category: entry.category,
      cacheable: entry.cacheable,
      cacheHit: false,
      ok: false,
      durationMs: performance.now() - start,
      bytesProcessed: 0,
      errorCode: err?.code ?? "UNKNOWN",
    };
  }
}

function sleep(ms: number): Promise<void> {
  return new Promise(r => setTimeout(r, ms));
}

// ────────────────────────────────────────────────────────────────────────────
// 7 success metrics
// ────────────────────────────────────────────────────────────────────────────

interface SuccessMetrics {
  /** 1. Total URLs attempted. */
  totalUrls: number;
  /** 2. Throughput (URLs/sec) over the active run window. */
  urlsPerSec: number;
  /** 3. Success rate (0..1) — fraction of ok=true. */
  successRate: number;
  /** 4. Cache hit rate (0..1) — fraction of cacheable entries that hit. */
  cacheHitRate: number;
  /** 5. p50 latency in ms. */
  p50LatencyMs: number;
  /** 6. p95 latency in ms. */
  p95LatencyMs: number;
  /** 7. p99 latency in ms. */
  p99LatencyMs: number;
  /** Bonus context: error distribution by code. */
  errorsByCode: Record<string, number>;
  /** Bonus context: per-category success rate. */
  perCategorySuccess: Record<string, { total: number; ok: number }>;
}

function percentile(sorted: number[], p: number): number {
  if (sorted.length === 0) return 0;
  const idx = Math.min(
    sorted.length - 1,
    Math.floor((p / 100) * sorted.length),
  );
  return sorted[idx];
}

function computeMetrics(
  results: PipelineResult[],
  wallMs: number,
): SuccessMetrics {
  const totalUrls = results.length;
  const ok = results.filter(r => r.ok);
  const successRate = totalUrls === 0 ? 0 : ok.length / totalUrls;
  const cacheable = results.filter(r => r.cacheable);
  const cacheHitRate =
    cacheable.length === 0
      ? 0
      : cacheable.filter(r => r.cacheHit).length / cacheable.length;

  const lats = ok.map(r => r.durationMs).sort((a, b) => a - b);
  const urlsPerSec = wallMs === 0 ? 0 : (totalUrls / wallMs) * 1000;

  const errorsByCode: Record<string, number> = {};
  for (const r of results) {
    if (!r.ok && r.errorCode) {
      errorsByCode[r.errorCode] = (errorsByCode[r.errorCode] ?? 0) + 1;
    }
  }

  const perCategorySuccess: Record<string, { total: number; ok: number }> = {};
  for (const r of results) {
    const c = (perCategorySuccess[r.category] ??= { total: 0, ok: 0 });
    c.total += 1;
    if (r.ok) c.ok += 1;
  }

  return {
    totalUrls,
    urlsPerSec,
    successRate,
    cacheHitRate,
    p50LatencyMs: percentile(lats, 50),
    p95LatencyMs: percentile(lats, 95),
    p99LatencyMs: percentile(lats, 99),
    errorsByCode,
    perCategorySuccess,
  };
}

// ────────────────────────────────────────────────────────────────────────────
// Driver — bounded worker pool over the corpus
// ────────────────────────────────────────────────────────────────────────────

async function runBench(corpus: Corpus): Promise<SuccessMetrics> {
  const rand = rng(corpus.seed);
  const deadline = Date.now() + DURATION_SEC * 1000;
  const results: PipelineResult[] = [];
  let nextIdx = 0;

  async function worker(): Promise<void> {
    while (Date.now() < deadline) {
      const i = nextIdx++;
      if (i >= corpus.entries.length) {
        // Wrap around for the duration window so we measure steady-state
        // throughput, not cold-start. First 25 entries are skipped to
        // exclude warmup.
        nextIdx = 25;
        continue;
      }
      const entry = corpus.entries[i];
      const r = await processOne(entry, rand);
      results.push(r);
    }
  }

  const t0 = performance.now();
  await Promise.all(Array.from({ length: CONCURRENCY }, () => worker()));
  const wallMs = performance.now() - t0;

  // Trim warmup (first 25 results) so the metrics are steady-state.
  const steady = results.slice(25);
  return computeMetrics(steady, wallMs);
}

// ────────────────────────────────────────────────────────────────────────────
// CLI entry
// ────────────────────────────────────────────────────────────────────────────

function loadCorpus(p: string): Corpus {
  const abs = path.isAbsolute(p) ? p : path.resolve(process.cwd(), p);
  const raw = fs.readFileSync(abs, "utf8");
  const parsed = JSON.parse(raw) as Corpus;
  if (!parsed.entries || !Array.isArray(parsed.entries)) {
    throw new Error(`Corpus at ${abs} is missing 'entries' array`);
  }
  return parsed;
}

function formatMetric(name: string, value: number, fmt: "ms" | "pct" | "num") {
  if (fmt === "ms") return `${name.padEnd(22)} ${value.toFixed(2)} ms`;
  if (fmt === "pct") return `${name.padEnd(22)} ${(value * 100).toFixed(2)} %`;
  return `${name.padEnd(22)} ${value.toFixed(2)}`;
}

async function main() {
  console.log(`[bench] corpus:        ${CORPUS_PATH}`);
  console.log(`[bench] duration:      ${DURATION_SEC}s`);
  console.log(`[bench] concurrency:   ${CONCURRENCY}`);

  const corpus = loadCorpus(CORPUS_PATH);
  console.log(
    `[bench] corpus entries: ${corpus.entries.length} across ${corpus.categories.length} categories`,
  );

  const m = await runBench(corpus);

  console.log("\n[bench] ── 7 success metrics ───────────────────────────");
  console.log(formatMetric("1. total_urls", m.totalUrls, "num"));
  console.log(formatMetric("2. urls_per_sec", m.urlsPerSec, "num"));
  console.log(formatMetric("3. success_rate", m.successRate, "pct"));
  console.log(formatMetric("4. cache_hit_rate", m.cacheHitRate, "pct"));
  console.log(formatMetric("5. p50_latency", m.p50LatencyMs, "ms"));
  console.log(formatMetric("6. p95_latency", m.p95LatencyMs, "ms"));
  console.log(formatMetric("7. p99_latency", m.p99LatencyMs, "ms"));

  console.log("\n[bench] ── error distribution ────────────────────────");
  if (Object.keys(m.errorsByCode).length === 0) {
    console.log("  (none)");
  } else {
    for (const [code, n] of Object.entries(m.errorsByCode)) {
      console.log(`  ${code.padEnd(20)} ${n}`);
    }
  }

  console.log("\n[bench] ── per-category success ──────────────────────");
  for (const [cat, c] of Object.entries(m.perCategorySuccess)) {
    const rate = c.total === 0 ? 0 : c.ok / c.total;
    console.log(
      `  ${cat.padEnd(14)} ${c.ok}/${c.total}  (${(rate * 100).toFixed(1)}%)`,
    );
  }

  // Emit a machine-readable result so BENCH_RESULTS.md can be regenerated.
  const outPath =
    process.env.FIRECRAWL_BENCH_OUTPUT ??
    path.join(__dirname, "scrape-throughput.last.json");
  fs.writeFileSync(
    outPath,
    JSON.stringify(
      {
        generated_at: new Date().toISOString(),
        corpus: CORPUS_PATH,
        duration_sec: DURATION_SEC,
        concurrency: CONCURRENCY,
        metrics: m,
      },
      null,
      2,
    ),
  );
  console.log(`\n[bench] wrote ${outPath}`);
}

if (require.main === module) {
  main().catch(err => {
    console.error("[bench] fatal:", err);
    process.exit(1);
  });
}
